INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(220, 74, 1, 'comprehension',
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(220, 1, 'Cognitive science research was initially developed to validate PBL but later shifted its focus to lecture-based instruction when early results proved inconclusive.'),
(220, 2, 'Research in cognitive science confirmed that lecture-based instruction is the most effective method for all learners, prompting educators to refine rather than replace traditional approaches.'),
(220, 3, 'Findings from cognitive science demonstrated that active engagement in constructing meaning produces deeper learning than passive absorption, providing the empirical basis for PBL''s emergence.'),
(220, 4, 'PBL originated from teachers'' intuitive sense that students learn better through projects, and cognitive science research was subsequently conducted to justify this pre-existing practice.'),
(221, 1, 'Teachers in these schools may lack the resources, training, and support to implement PBL rigorously, potentially widening the gap between privileged and disadvantaged students.'),
(221, 2, 'Students in underfunded schools tend to reject PBL because they prefer the structure and predictability of traditional lecture-based instruction.'),
(221, 3, 'PBL is less expensive than traditional instruction, so underfunded schools are pressured to adopt it as a cost-saving measure regardless of its educational merits.'),
(221, 4, 'Standardized test scores invariably decline when PBL is introduced in underfunded schools, making it impossible to measure student progress accurately.'),
(222, 1, 'an unsustainable burden on already overworked teachers who lack adequate administrative support and compensation'),
(222, 2, 'a privilege reserved for students in well-resourced environments rather than a universal pedagogical improvement'),
(222, 3, 'a marketing tool for technology companies seeking to sell digital platforms to school districts at inflated prices'),
(222, 4, 'an inferior version of traditional instruction that sacrifices content depth for superficial engagement and entertainment');
